module RefModule(
    input clk,
    input reset,
    input ena,
    input d,
    output reg [7:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the shift register to zero
            q <= 8'b00000000;
        end else if (ena) begin
            // Enable: Shift left and input new data
            q <= {q[6:0], d};
        end
    end

endmodule
